30: // dynamicLister implements the Lister interface.
31: type dynamicLister struct {
32: 	indexer cache.Indexer
33: 	gvr     schema.GroupVersionResource
34: }
35: 
36: // New returns a new Lister.
37: func New(indexer cache.Indexer, gvr schema.GroupVersionResource) Lister {
38: 	return &dynamicLister{indexer: indexer, gvr: gvr}
39: }
