61: // Namespace returns an object that can list and get resources from a given namespace.
62: func (l *dynamicLister) Namespace(namespace string) NamespaceLister {
63: 	return &dynamicNamespaceLister{indexer: l.indexer, namespace: namespace, gvr: l.gvr}
